const body = $input.first().json.body || $input.first().json;
const crypto = require('crypto');
const jobId = crypto.randomUUID();
let repoUrl = body.repoUrl || '';
let repoName = body.repoName || '';
let owner = body.owner || '';
const token = body.token || '';
if (repoUrl && (!repoName || !owner)) {
  const match = repoUrl.match(/github\.com\/([^\/]+)\/([^\/]+)/);
  if (match) {
    owner = owner || match[1];
    repoName = repoName || match[2].replace(/\.git$/, '');
  }
}
if (!repoName || !owner) throw new Error('Missing: owner and repoName (or valid GitHub repoUrl)');
return [{
  json: {
    jobId,
    repoUrl: repoUrl || ('https://github.com/' + owner + '/' + repoName),
    repoName,
    owner,
    token,
    startedAt: new Date().toISOString()
  }
}];

const input = $('Extract Input').item.json;
const repoInfo = $('Get Repo Info').item.json;
const treeData = $('Get File Tree').item.json;

let packageJsonStr = '{}';
try {
  const pkgNode = $('Get package.json').item.json;
  if (pkgNode && pkgNode.content)
    packageJsonStr = Buffer.from(pkgNode.content, 'base64').toString('utf8').substring(0, 2500);
} catch(e) {}

let readmeStr = 'No README found.';
try {
  const readmeNode = $('Get README.md').item.json;
  if (readmeNode && readmeNode.content)
    readmeStr = Buffer.from(readmeNode.content, 'base64').toString('utf8').substring(0, 3000);
} catch(e) {}

const tree = Array.isArray(treeData.tree) ? treeData.tree.filter(f => f.type === 'blob') : [];
const total = tree.length;
const sourceExts = ['.ts','.tsx','.js','.jsx','.py','.go','.java','.rs','.rb','.php','.cs','.vue','.svelte'];
const sourceFiles = tree.filter(f => {
  const p = f.path.toLowerCase();
  return sourceExts.some(e => p.endsWith(e)) &&
    !p.includes('node_modules/') && !p.includes('dist/') &&
    !p.includes('build/') && !p.includes('.min.');
}).slice(0, 120);

const moduleMap = {};
sourceFiles.forEach(f => {
  const top = f.path.includes('/') ? f.path.split('/')[0] : 'root';
  if (!moduleMap[top]) moduleMap[top] = [];
  moduleMap[top].push(f.path);
});

const now = new Date().toISOString();
const lang = repoInfo.language || 'Unknown';
const desc = repoInfo.description || 'No description.';
const fileListStr = sourceFiles.map(f => f.path).join('\n').substring(0, 5000);

const userPrompt = [
  'Analyze this GitHub repository for Branchy.io and return ONLY valid raw JSON. No markdown, no explanation.',
  '',
  '## Repository',
  '- Name: ' + input.repoName,
  '- Owner: ' + input.owner,
  '- URL: ' + input.repoUrl,
  '- Description: ' + desc,
  '- Language: ' + lang,
  '- Stars: ' + (repoInfo.stargazers_count || 0),
  '- Total Files: ' + total,
  '- Source Files: ' + sourceFiles.length,
  '',
  '## package.json',
  packageJsonStr,
  '',
  '## README',
  readmeStr,
  '',
  '## Directory Structure',
  JSON.stringify(moduleMap, null, 2).substring(0, 3500),
  '',
  '## Source File Paths',
  fileListStr,
  '',
  '## Return this JSON schema (replace ALL placeholder values with real analysis):',
  '{',
  '  "repoId": "' + input.jobId + '",',
  '  "repoName": "' + input.repoName + '",',
  '  "owner": "' + input.owner + '",',
  '  "language": "detected_language",',
  '  "filesCount": ' + total + ',',
  '  "healthScore": 75,',
  '  "analyzedAt": "' + now + '",',
  '  "modules": [',
  '    {"id":"mod-1","name":"Core","type":"core","filePath":"src/index.ts","loc":120,"dependsOn":[],"usedBy":[],"summary":"Main entry"}',
  '  ],',
  '  "insights": [{"type":"info","text":"Uses TypeScript","fileName":"tsconfig.json"}],',
  '  "complexityByFile": [{"fileName":"index.ts","filePath":"src/index.ts","complexity":30,"level":"low"}],',
  '  "circularDeps": [],',
  '  "deadCode": [],',
  '  "onboardingGuide": {',
  '    "sections": [',
  '      {"title":"Overview","type":"overview","content":"Project overview"},',
  '      {"title":"Tech Stack","type":"techStack","content":{"frontend":[],"backend":[],"database":[],"devtools":[]}},',
  '      {"title":"Structure","type":"structure","content":"Directory structure"},',
  '      {"title":"Key Modules","type":"modules","content":"Main modules"},',
  '      {"title":"Getting Started","type":"gettingStarted","content":"Setup steps"},',
  '      {"title":"Patterns","type":"patterns","content":"Arch patterns"},',
  '      {"title":"Run Locally","type":"runLocally","content":{"steps":["Clone","Install"],"commands":["npm install","npm run dev"]}}',
  '    ],',
  '    "generatedAt": "' + now + '"',
  '  },',
  '  "healthReport": {',
  '    "overallScore": 75, "maintainability": 70, "testCoverage": 20, "documentation": 60,',
  '    "issues": [{"id":"i-1","severity":"warning","fileName":"file.ts","filePath":"src/file.ts","title":"Missing tests","description":"No test files found","suggestedFix":"Add unit tests","resolved":false}]',
  '  },',
  '  "changelogs": []',
  '}',
  '',
  'Rules: generate 6-15 modules, 5-10 insights, 5-10 complexityByFile items, 3-6 health issues. All scores are integers 0-100.'
].join('\n');

return [{
  json: {
    jobId: input.jobId,
    repoUrl: input.repoUrl,
    repoName: input.repoName,
    owner: input.owner,
    language: lang,
    filesCount: total,
    requestBody: {
      model: 'claude-opus-4-6',
      max_tokens: 8192,
      system: 'You are an expert software architect. Return ONLY valid raw JSON, no markdown, no explanations.',
      messages: [{ role: 'user', content: userPrompt }]
    }
  }
}];

const prepared = $('Prepare AI Prompt').item.json;
const claudeResp = $input.first().json;
let analysisResult = null;
let success = false;
let errorMsg = '';

try {
  if (claudeResp.error)
    throw new Error('Anthropic error: ' + (claudeResp.error.message || JSON.stringify(claudeResp.error)));
  const content = claudeResp.content;
  if (!Array.isArray(content) || !content.length)
    throw new Error('Empty Claude response');
  const textBlock = content.find(c => c.type === 'text');
  if (!textBlock) throw new Error('No text block in response');
  let jsonStr = textBlock.text.trim();
  jsonStr = jsonStr.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  analysisResult = JSON.parse(jsonStr);
  analysisResult.repoId = analysisResult.repoId || prepared.jobId;
  analysisResult.repoName = analysisResult.repoName || prepared.repoName;
  analysisResult.owner = analysisResult.owner || prepared.owner;
  analysisResult.language = analysisResult.language || prepared.language || 'Unknown';
  analysisResult.filesCount = analysisResult.filesCount || prepared.filesCount || 0;
  analysisResult.healthScore = Number(analysisResult.healthScore) || 0;
  analysisResult.analyzedAt = analysisResult.analyzedAt || new Date().toISOString();
  analysisResult.modules = Array.isArray(analysisResult.modules) ? analysisResult.modules : [];
  analysisResult.insights = Array.isArray(analysisResult.insights) ? analysisResult.insights : [];
  analysisResult.complexityByFile = Array.isArray(analysisResult.complexityByFile) ? analysisResult.complexityByFile : [];
  analysisResult.circularDeps = Array.isArray(analysisResult.circularDeps) ? analysisResult.circularDeps : [];
  analysisResult.deadCode = Array.isArray(analysisResult.deadCode) ? analysisResult.deadCode : [];
  analysisResult.changelogs = Array.isArray(analysisResult.changelogs) ? analysisResult.changelogs : [];
  if (!analysisResult.onboardingGuide)
    analysisResult.onboardingGuide = { sections: [], generatedAt: new Date().toISOString() };
  if (!analysisResult.healthReport)
    analysisResult.healthReport = { overallScore: 70, maintainability: 70, testCoverage: 0, documentation: 50, issues: [] };
  success = true;
} catch(e) {
  errorMsg = e.message;
  analysisResult = {
    repoId: prepared.jobId, repoName: prepared.repoName, owner: prepared.owner,
    language: prepared.language || 'Unknown', filesCount: prepared.filesCount || 0,
    healthScore: 0, analyzedAt: new Date().toISOString(),
    modules: [], insights: [{ type: 'error', text: 'Analysis failed: ' + errorMsg }],
    complexityByFile: [], circularDeps: [], deadCode: [], changelogs: [],
    onboardingGuide: { sections: [], generatedAt: new Date().toISOString() },
    healthReport: { overallScore: 0, maintainability: 0, testCoverage: 0, documentation: 0, issues: [] }
  };
}

return [{ json: { jobId: prepared.jobId, analysisResult, success, errorMsg } }];
